class Solution:
    def repeatedCharacter(self, s: str) -> str:
        char_count = {}
        for char in s:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1
        for char in s:
            if char_count[char] == 2:
                return char
